// Conditional, dynamic import using top-level await (ES2022)
const loadComponent = async (componentName) => {
  switch (componentName) {
    case 'chart':
      return (await import('./chart-library.js')).ChartComponent;
    case 'map':
      return (await import('./map-library.js')).MapWidget;
    default:
      return null;
  }
};

// Example usage
const Chart = await loadComponent('chart');
if (Chart) {
  new Chart().render('#chart-container');
}

